contracts/BaluniPod_v1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
	function transfer(
		address recipient,
		uint256 amount
	) external returns (bool);

	function transferFrom(
		address sender,
		address recipient,
		uint256 amount
	) external returns (bool);

	function balanceOf(address account) external view returns (uint256);

	function approve(address spender, uint256 amount) external returns (bool);
}

contract BaluniPodV1 {
	struct Pod {
		address seller;
		address[] erc20Tokens;
		uint256[] tokenAmounts;
		uint256 priceInUSDC;
	}

	Pod[] public pods;
	mapping(uint256 => bool) public podIsActive; // Aggiunto per tracciare lo stato attivo dei Pod
	mapping(address => uint256[]) public sellerPods;
	IERC20 public USDC; // Interfaccia del contratto USDC

	event PodCreated(uint256 indexed podId, address seller);
	event PodPurchased(uint256 indexed podId, address buyer);
	event PodWithdrawn(uint256 indexed podId, address seller);

	constructor(address _usdcAddress) {
		USDC = IERC20(_usdcAddress);
	}

	function createPod(
		address[] memory _erc20Tokens,
		uint256[] memory _tokenAmounts,
		uint256 _priceInUSDC
	) public {
		require(
			_erc20Tokens.length == _tokenAmounts.length,
			"Tokens and amounts mismatch"
		);
		require(_erc20Tokens.length > 0, "At least one token required");

		pods.push(
			Pod({
				seller: msg.sender,
				erc20Tokens: _erc20Tokens,
				tokenAmounts: _tokenAmounts,
				priceInUSDC: _priceInUSDC
			})
		);

		uint256 podId = pods.length - 1;
		podIsActive[podId] = true; // Imposta il Pod come attivo
		sellerPods[msg.sender].push(podId);

		emit PodCreated(podId, msg.sender);
	}

	function buyPod(uint256 podId) public {
		require(podIsActive[podId], "Pod is not active");
		Pod storage pod = pods[podId];

		require(
			USDC.transferFrom(msg.sender, pod.seller, pod.priceInUSDC),
			"USDC transfer failed"
		);

		for (uint i = 0; i < pod.erc20Tokens.length; i++) {
			require(
				IERC20(pod.erc20Tokens[i]).transfer(
					msg.sender,
					pod.tokenAmounts[i]
				),
				"Token transfer failed"
			);
		}

		podIsActive[podId] = false; // Imposta il Pod come non attivo
		emit PodPurchased(podId, msg.sender);
	}

	function withdrawPod(uint256 podId) public {
		require(podIsActive[podId], "Pod is not active");
		Pod storage pod = pods[podId];
		require(msg.sender == pod.seller, "Only seller can withdraw");

		for (uint i = 0; i < pod.erc20Tokens.length; i++) {
			require(
				IERC20(pod.erc20Tokens[i]).transfer(
					pod.seller,
					pod.tokenAmounts[i]
				),
				"Token return failed"
			);
		}

		podIsActive[podId] = false; // Imposta il Pod come non attivo

		// Nessuna necessità di rimuovere il pod dall'array del venditore per ottimizzazione
		emit PodWithdrawn(podId, msg.sender);
	}

	function getPodsBySeller(
		address seller
	) public view returns (uint256[] memory) {
		return sellerPods[seller];
	}

	function getPodsByUser(
		address user
	) public view returns (uint256[] memory) {
		return sellerPods[user];
	}

	function getActivePods() public view returns (Pod[] memory) {
		uint256 activeCount = 0;
		for (uint256 i = 0; i < pods.length; i++) {
			if (podIsActive[i]) {
				activeCount++;
			}
		}

		Pod[] memory activePods = new Pod[](activeCount);
		uint256 activeIndex = 0;
		for (uint256 i = 0; i < pods.length; i++) {
			if (podIsActive[i]) {
				activePods[activeIndex] = pods[i];
				activeIndex++;
			}
		}
		return activePods;
	}
}

contracts/BaluniPool_v1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import "./Oracle.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "./interfaces/IWETH.sol";
import "./interfaces/IVault.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract BaluniPoolV1 is ReentrancyGuard {
	Oracle public oracle;

	enum Coin {
		MATIC
	}

	struct Prediction {
		address predictor;
		Coin token;
		uint256 predictedPrice;
		uint256 actualPrice;
		uint256 resolvedPrice;
		uint256 difference;
		uint256 timestamp;
		uint256 endTime;
		bool resolved;
	}

	Prediction[] public predictions;

	IWETH public wnative;
	IVault public yearnVault;

	uint256 public submissionBaseFee = 0.01 ether;
	uint256 public submissionStepFee = 0.001 ether;
	uint256 public predictionDuration = 1 days;
	uint256 public resolutionLimit = 10 minutes;
	uint256 public exitLimit = 7 days;
	uint256 public totalPredictions = 0;
	uint256 public totalDistribution = 0;

	mapping(address => uint256) public distributionCounter;
	mapping(address => uint256) public lastWithdraw;
	mapping(address => uint256) public userSubmissionFees;

	event PredictionRegistered(
		address indexed predictor,
		Coin token,
		uint256 predictedPrice,
		uint256 actualPrice,
		uint256 timestamp,
		uint256 endTime
	);
	event RewardWithdrawn(address indexed predictor, uint256 amount);

	constructor(
		address _oracleAddress,
		address _wnative,
		address _yearnVault
	) ReentrancyGuard() {
		oracle = Oracle(_oracleAddress);
		wnative = IWETH(_wnative);
		yearnVault = IVault(_yearnVault);
	}

	function getSubmissionFee() public view returns (uint256) {
		return userSubmissionFees[msg.sender];
	}

	function submit(Coin _token, uint256 _predictedPrice) public payable {
		require(msg.value >= submissionBaseFee, "Invalid fee amount");
		require(
			msg.value >= userSubmissionFees[msg.sender],
			"Invalid fee amount"
		);

		userSubmissionFees[msg.sender] = msg.value;
		userSubmissionFees[msg.sender] += submissionStepFee;

		uint256 price = oracle.getLatestPrice() * 1e10;

		predictions.push(
			Prediction(
				msg.sender,
				_token,
				_predictedPrice,
				price,
				0,
				0,
				block.timestamp,
				block.timestamp + predictionDuration,
				false
			)
		);

		totalPredictions++;
		wnative.deposit{ value: msg.value }();
		IERC20(address(wnative)).approve(address(yearnVault), msg.value);
		yearnVault.deposit(msg.value, address(this));

		emit PredictionRegistered(
			msg.sender,
			_token,
			_predictedPrice,
			price,
			block.timestamp,
			block.timestamp + predictionDuration
		);
	}

	function exit() public {
		require(
			block.timestamp - lastWithdraw[msg.sender] >= exitLimit,
			"Wait for exitLimit before next withdraw"
		);

		uint256 reward = calculateReward(msg.sender);

		require(reward > 0, "No reward available");

		IERC20(address(yearnVault)).approve(address(yearnVault), reward);

		uint256 ctxBalanceB4 = address(this).balance;
		yearnVault.withdraw(reward, address(this), address(this), 200);
		uint256 ctxBalanceAfter = address(this).balance;
		uint256 rewardToTransfer = ctxBalanceAfter - ctxBalanceB4;

		wnative.withdraw(rewardToTransfer);

		// Aggiornamento dello stato prima della trasferimento per prevenire reentrancy
		totalPredictions -= distributionCounter[msg.sender];
		distributionCounter[msg.sender] = 0;
		lastWithdraw[msg.sender] = block.timestamp;

		userSubmissionFees[msg.sender] = submissionBaseFee;

		Address.sendValue(payable(msg.sender), rewardToTransfer);

		emit RewardWithdrawn(msg.sender, rewardToTransfer);
	}

	function calculateReward(address user) public view returns (uint256) {
		require(distributionCounter[user] > 0, "No predictions made");
		require(totalDistribution > 0, "No rewards available");
		uint256 userShare = (distributionCounter[user] * 1e18) /
			totalDistribution;
		uint256 yeanBalance = IERC20(address(yearnVault)).balanceOf(
			address(this)
		);
		uint256 userBalance = (yeanBalance * userShare) / 1e18;
		uint256 userReward = userBalance - userBalance / 2;
		return userReward;
	}

	function last10Predictions() public view returns (Prediction[] memory) {
		uint256 length = predictions.length;
		uint256 start = length > 10 ? length - 10 : 0;
		Prediction[] memory result = new Prediction[](length - start);
		for (uint256 i = start; i < length; i++) {
			result[i - start] = predictions[i];
		}
		return result;
	}

	function getPrediction(
		uint256 index
	) public view returns (Prediction memory) {
		require(index < predictions.length, "Invalid index");
		return predictions[index];
	}

	function getPredictionFromTo(
		uint256 from,
		uint256 to
	) public view returns (Prediction[] memory) {
		require(from < to, "Invalid range");
		require(to <= predictions.length, "Invalid range");
		Prediction[] memory result = new Prediction[](to - from);
		for (uint256 i = from; i < to; i++) {
			result[i - from] = predictions[i];
		}
		return result;
	}

	function getPredictionCount() public view returns (uint256) {
		return predictions.length;
	}

	function getTotalPredictions() public view returns (uint256) {
		return totalPredictions;
	}

	function hasAnyUnresolvedPastEndTime() public view returns (bool) {
		for (uint256 i = 0; i < predictions.length; i++) {
			if (
				!predictions[i].resolved &&
				block.timestamp > predictions[i].endTime
			) {
				return true; // Restituisce true alla prima occorrenza di una previsione non risolta superata da endTime
			}
		}
		return false; // Se nessuna previsione non risolta ha superato endTime, restituisce false
	}

	function resolve() public {
		uint256 latestPrice = oracle.getLatestPrice() * 1e10;

		for (uint256 i = 0; i < predictions.length; i++) {
			if (
				!predictions[i].resolved &&
				block.timestamp >= predictions[i].endTime
			) {
				uint256 predictedPrice = predictions[i].predictedPrice;
				uint256 priceDifference = predictedPrice > latestPrice
					? predictedPrice - latestPrice
					: latestPrice - predictedPrice;
				uint256 score = calculateScore(predictedPrice, latestPrice);

				if (
					block.timestamp <= predictions[i].endTime + resolutionLimit
				) {
					distributionCounter[predictions[i].predictor] += 0; // Assumi che esista questo campo
				} else {
					distributionCounter[predictions[i].predictor] += score; // Assumi che esista questo campo
				}

				predictions[i].difference = priceDifference;
				predictions[i].resolved = true;
				predictions[i].resolvedPrice = latestPrice;
				totalDistribution += score;
			}
		}

		distributionCounter[msg.sender]++;
		totalDistribution++;
	}

	function calculateScore(
		uint256 predictedPrice,
		uint256 resolvedPrice
	) private pure returns (uint256) {
		if (resolvedPrice == 0) return 1; // Evita divisione per zero
		uint256 priceDifference = predictedPrice > resolvedPrice
			? predictedPrice - resolvedPrice
			: resolvedPrice - predictedPrice;
		uint256 differencePercentage = (priceDifference * 100) / resolvedPrice;

		// Il punteggio diminuisce all'aumentare della differenza percentuale
		if (differencePercentage == 0) {
			return 10; // Puntaeggio massimo per previsione perfetta
		} else if (differencePercentage <= 5) {
			return 9;
		} else if (differencePercentage <= 10) {
			return 8;
		} else if (differencePercentage <= 15) {
			return 7;
		} else if (differencePercentage <= 20) {
			return 6;
		} else if (differencePercentage <= 25) {
			return 5;
		} else if (differencePercentage <= 30) {
			return 4;
		} else if (differencePercentage <= 35) {
			return 3;
		} else if (differencePercentage <= 40) {
			return 2;
		} else {
			return 1; // Punteggio minimo per grande differenza
		}
	}

	function hasUnresolvedPredictions() public view returns (bool) {
		for (uint256 i = 0; i < predictions.length; i++) {
			if (!predictions[i].resolved) {
				return true;
			}
		}
		return false;
	}

	// Permetti al contratto di ricevere ETH
	receive() external payable {}
}

contracts/BaluniTournament_v1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./Oracle.sol";

contract BaluniTournamentV1 is ReentrancyGuard {
	Oracle public oracle;

	uint256 public keeperPercentageFee = 100;
	uint256 public submissionEndTime = 8 hours;
	uint256 public verificationEndTime = 1 days;
	uint256 public resolutionEndTime = 1 hours;

	struct Prediction {
		uint256 round;
		address predictor;
		uint256 predictedPrice;
		uint256 amount;
	}

	uint256 public maxParticipants;

	uint256 public lastRoundPrice;

	Prediction[] public predictions;

	uint256 public verificationTime;
	address public priceFeedAddress;
	uint256 public prizePool;
	uint256 public currentRound = 0;

	mapping(uint256 => uint256) scores;
	mapping(uint256 => uint256) prizePerScore;

	address[] public roundWinners;

	struct WinnerInfo {
		uint256 index;
		uint256 difference;
		bool exists;
	}

	event PredictionSubmitted(
		uint256 round,
		address indexed predictor,
		uint256 predictedPrice,
		uint256 amount
	);

	event TournamentResolved(
		uint256 round,
		address[] winners,
		uint256[] prizeAmounts
	);

	constructor(
		address _oracleAddress,
		uint256 _maxParticipants
	) ReentrancyGuard() {
		oracle = Oracle(_oracleAddress);
		maxParticipants = _maxParticipants;
		verificationTime = block.timestamp + verificationEndTime;
	}

	function isRoundOpen() public view returns (bool) {
		return block.timestamp <= verificationTime - 4 hours;
	}

	function submitPrediction(uint256 _predictedPrice) external payable {
		require(msg.value >= 0.01 ether, "Entry fee is 0.01 ether");
		require(
			predictions.length < maxParticipants,
			"Participant limit reached"
		);
		require(
			block.timestamp <= verificationTime - submissionEndTime,
			"Submissions closed 4 hours before round ends"
		);

		predictions.push(
			Prediction(currentRound, msg.sender, _predictedPrice, msg.value)
		);
		prizePool += msg.value;
		emit PredictionSubmitted(
			currentRound,
			msg.sender,
			_predictedPrice,
			msg.value
		);
	}

	function _resetTournament() private {
		delete predictions;
		prizePool = 0;
		verificationTime = block.timestamp + verificationEndTime;
		currentRound += 1;
	}

	function resolveTournament() external nonReentrant {
		require(
			block.timestamp >= verificationTime,
			"Tournament cannot be resolved yet"
		);

		if (block.timestamp >= verificationTime + resolutionEndTime) {
			for (uint256 i = 0; i < predictions.length; i++) {
				Address.sendValue(
					payable(predictions[i].predictor),
					predictions[i].amount
				);
			}
			emit TournamentResolved(
				currentRound,
				new address[](0),
				new uint256[](0)
			);
			_resetTournament();
			return;
		}

		uint256 actualPrice = oracle.getLatestPrice();
		uint256 actualPriceUint = actualPrice * 1e10;
		lastRoundPrice = actualPriceUint;

		if (predictions.length == 0) {
			emit TournamentResolved(
				currentRound,
				new address[](0),
				new uint256[](0)
			);
			roundWinners = new address[](0);
			_resetTournament();
			return;
		}

		if (predictions.length == 1) {
			// Restituisce il premio all'unico partecipante
			address[] memory winnerAddress = new address[](1);
			uint256[] memory winnerPrize = new uint256[](1);
			winnerAddress[0] = predictions[0].predictor;
			winnerPrize[0] = prizePool;
			Address.sendValue(payable(winnerAddress[0]), winnerPrize[0]);
			emit TournamentResolved(currentRound, winnerAddress, winnerPrize);
			roundWinners = winnerAddress;
			_resetTournament();
			return;
		}

		if (predictions.length == 2) {
			// Distribuisci il premio tra i due partecipanti
			address[] memory winnersAddresses = new address[](2);
			uint256[] memory prizes = new uint256[](2);
			uint256 halfPrize = prizePool / 2;
			for (uint256 i = 0; i < 2; i++) {
				winnersAddresses[i] = predictions[i].predictor;
				prizes[i] = halfPrize;
				Address.sendValue(payable(winnersAddresses[i]), prizes[i]);
			}
			emit TournamentResolved(currentRound, winnersAddresses, prizes);
			roundWinners = winnersAddresses;
			_resetTournament();
			return;
		}

		WinnerInfo[3] memory winners;
		uint256 winnersCount = 0;

		// Identifica i potenziali vincitori e calcola la differenza di prezzo
		for (uint256 i = 0; i < predictions.length; i++) {
			uint256 difference = predictions[i].predictedPrice > actualPriceUint
				? predictions[i].predictedPrice - actualPriceUint
				: actualPriceUint - predictions[i].predictedPrice;

			if (winnersCount < 3) {
				winners[winnersCount] = WinnerInfo(i, difference, true);
				winnersCount++;
			} else {
				// Trova e sostituisci il vincitore con la differenza maggiore se ce n'è uno con una differenza minore
				uint256 maxDiffIndex = 0;
				uint256 maxDiff = winners[0].difference;
				for (uint256 j = 1; j < 3; j++) {
					if (winners[j].difference > maxDiff) {
						maxDiff = winners[j].difference;
						maxDiffIndex = j;
					}
				}

				if (difference < maxDiff) {
					winners[maxDiffIndex] = WinnerInfo(i, difference, true);
				}
			}
		}

		uint256 keeperFee = (prizePool * keeperPercentageFee) / 10000;
		prizePool -= keeperFee;
		Address.sendValue(payable(msg.sender), keeperFee);

		uint256 totalPrize = prizePool;

		// Preparazione degli array per i vincitori e i premi
		address[] memory finalWinnersAddresses = new address[](winnersCount);
		uint256[] memory finalPrizeAmounts = new uint256[](winnersCount);

		for (uint256 i = 0; i < winnersCount; i++) {
			finalWinnersAddresses[i] = predictions[winners[i].index].predictor;
			// Distribuzione equa del premio
			finalPrizeAmounts[i] = totalPrize / winnersCount;
			Address.sendValue(
				payable(finalWinnersAddresses[i]),
				finalPrizeAmounts[i]
			);
		}

		roundWinners = finalWinnersAddresses;

		emit TournamentResolved(
			currentRound,
			finalWinnersAddresses,
			finalPrizeAmounts
		);
		_resetTournament();
	}

	function getLastWinners() external view returns (address[] memory) {
		return roundWinners;
	}

	function getPrice() public view returns (uint256) {
		return oracle.getLatestPrice() * 1e10;
	}

	function getLatestRoundPrice() external view returns (uint256) {
		return lastRoundPrice;
	}

	function getCurrentRound() external view returns (uint256) {
		return currentRound;
	}

	function getMaxPartecipants() external view returns (uint256) {
		return maxParticipants;
	}

	function getCurrentRoundPartecipants() external view returns (uint256) {
		return predictions.length;
	}

	function getCurrentPricePool() external view returns (uint256) {
		return prizePool;
	}

	function getNextVerificationTime() external view returns (uint256) {
		return verificationTime;
	}

	function getPredictions() external view returns (Prediction[] memory) {
		return predictions;
	}

	function getPartecipants() external view returns (address[] memory) {
		address[] memory partecipants = new address[](predictions.length);
		for (uint256 i = 0; i < predictions.length; i++) {
			partecipants[i] = predictions[i].predictor;
		}
		return partecipants;
	}

	receive() external payable {
		prizePool += msg.value;
	}
}

